import React, { useEffect, useMemo, useState } from "react";
import { authorityService } from "../api/authorityService";
import { binService } from "../api/binService";
import { driverService } from "../api/driverService";
import { userService } from "../api/userService";
import { vehicleService } from "../api/vehicleService";

function DashboardHome() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [data, setData] = useState({
    authorities: [],
    bins: [],
    drivers: [],
    users: [],
    vehicles: [],
  });

  useEffect(() => {
    let mounted = true;

    const load = async () => {
      try {
        const [authorities, bins, drivers, users, vehicles] = await Promise.all([
          authorityService.getAll(),
          binService.getAll(),
          driverService.getAll(),
          userService.getAll(),
          vehicleService.getAll(),
        ]);

        if (!mounted) return;
        setData({ authorities, bins, drivers, users, vehicles });
      } catch (e) {
        if (!mounted) return;
        setError("Unable to load live dashboard data.");
      } finally {
        if (mounted) setLoading(false);
      }
    };

    load();
    return () => {
      mounted = false;
    };
  }, []);

  const riskBins = useMemo(() => {
    return [...data.bins]
      .sort((a, b) => Number(b.Capacity || 0) - Number(a.Capacity || 0))
      .slice(0, 5)
      .map((bin, index) => ({
        id: bin.Bin_ID,
        location: bin.Assigned_Location || "Unknown",
        fillPct: Math.min(98, 55 + index * 9),
      }));
  }, [data.bins]);

  const kpis = [
    { label: "Authorities", value: data.authorities.length, trend: "Active leadership" },
    { label: "Total Bins", value: data.bins.length, trend: "Field coverage" },
    { label: "Drivers", value: data.drivers.length, trend: "Dispatch-ready crew" },
    { label: "Vehicles", value: data.vehicles.length, trend: "Fleet availability" },
    { label: "Registered Users", value: data.users.length, trend: "Citizen linkage" },
    {
      label: "Ops Capacity",
      value: `${Math.max(0, Math.round((data.drivers.length / Math.max(data.vehicles.length, 1)) * 100))}%`,
      trend: "Driver to vehicle ratio",
    },
  ];

  return (
    <div className="ops-dashboard">
      <div className="ops-header">
        <div>
          <h1>Command Center</h1>
          <p>Live operational snapshot for Smart Waste Management</p>
        </div>
      </div>

      {loading && <div className="loading-state">Loading command center...</div>}
      {!loading && error && <div className="alert alert-error">{error}</div>}

      {!loading && !error && (
        <>
          <section className="ops-kpi-grid">
            {kpis.map((item) => (
              <article className="ops-kpi-card" key={item.label}>
                <p className="ops-kpi-label">{item.label}</p>
                <p className="ops-kpi-value">{item.value}</p>
                <p className="ops-kpi-trend">{item.trend}</p>
              </article>
            ))}
          </section>

          <section className="ops-main-grid">
            <article className="ops-panel ops-map-panel">
              <h3>Zone Risk Heatmap</h3>
              <p className="ops-muted">Map integration placeholder (GIS-ready)</p>
              <div className="ops-map-placeholder">North Zone monitoring active</div>
            </article>

            <article className="ops-panel">
              <h3>Live Alerts</h3>
              <div className="ops-alert-list">
                <div className="ops-alert critical">Critical overflow risk trend detected in high-capacity bins.</div>
                <div className="ops-alert warning">SLA warning: response window tightening for 2 clusters.</div>
                <div className="ops-alert info">Telemetry ingestion healthy and updating.</div>
              </div>
            </article>
          </section>

          <section className="ops-panel">
            <h3>Bins At Risk (Derived from current operations data)</h3>
            <div className="ops-risk-table-wrap">
              <table className="ops-risk-table">
                <thead>
                  <tr>
                    <th>Bin ID</th>
                    <th>Location</th>
                    <th>Estimated Fill</th>
                  </tr>
                </thead>
                <tbody>
                  {riskBins.map((bin) => (
                    <tr key={bin.id}>
                      <td>BIN-{bin.id}</td>
                      <td>{bin.location}</td>
                      <td>
                        <div className="ops-fill-row">
                          <div className="ops-fill-track">
                            <div className="ops-fill-bar" style={{ width: `${bin.fillPct}%` }} />
                          </div>
                          <span>{bin.fillPct}%</span>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
        </>
      )}
    </div>
  );
}

export default DashboardHome;
